import{_ as a,o as t,c as r,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Manual Attributes & Status Overrides","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/manual-attributes.md","filePath":"how-to/manual-attributes.md"}'),o={name:"how-to/manual-attributes.md"};function s(l,e,n,h,u,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="manual-attributes-status-overrides" tabindex="-1">Manual Attributes &amp; Status Overrides <a class="header-anchor" href="#manual-attributes-status-overrides" aria-label="Permalink to &quot;Manual Attributes &amp; Status Overrides&quot;">​</a></h1><p>Manual attributes are for human judgment that should sit on top of normal player tracking. Status overrides are the stronger version: they tell the app which status to treat as the player&#39;s main one until you clear it.</p><h2 id="open-the-tools" tabindex="-1">Open the tools <a class="header-anchor" href="#open-the-tools" aria-label="Permalink to &quot;Open the tools&quot;">​</a></h2><ol><li>Open the player&#39;s profile.</li><li>Go to <strong>Player Attributes</strong>.</li></ol><h2 id="assign-a-manual-attribute" tabindex="-1">Assign a manual attribute <a class="header-anchor" href="#assign-a-manual-attribute" aria-label="Permalink to &quot;Assign a manual attribute&quot;">​</a></h2><ol><li>Choose an attribute from <strong>Assign manual attribute</strong>.</li><li>Add a short reason if useful.</li><li>Select <strong>Assign</strong>.</li></ol><p>This is a good fit when you want to record a decision that analytics alone should not guess.</p><h2 id="save-a-status-override" tabindex="-1">Save a status override <a class="header-anchor" href="#save-a-status-override" aria-label="Permalink to &quot;Save a status override&quot;">​</a></h2><p>Use the override controls when the player&#39;s main status should be forced to a specific value for now.</p><p>You can:</p><ul><li>choose the override status</li><li>add an override reason</li><li>save the override</li><li>clear the override later</li></ul><h2 id="what-is-the-difference" tabindex="-1">What is the difference <a class="header-anchor" href="#what-is-the-difference" aria-label="Permalink to &quot;What is the difference&quot;">​</a></h2><ul><li>A manual attribute adds information.</li><li>A status override changes which status the tracker should treat as primary.</li></ul><p>That means an override is more direct and should be used more carefully.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Leave a short reason whenever another admin may need to understand the decision later.</li><li>Clear overrides when they are no longer true.</li><li>Recheck the player&#39;s graphs and recent records if the manual decision affects how you read their activity.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./player-profile.html">Read a Player Profile</a></li><li><a href="./players-directory.html">Browse &amp; Filter Players</a></li><li><a href="./../getting-started/dashboard-tour.html">Read the Dashboard</a></li></ul>',18)])])}const p=a(o,[["render",s]]);export{m as __pageData,p as default};
